@@ -1381,6 +1381,7 @@ public:
 private:
   /// A CallbackVH to arrange for ScalarEvolution to be notified whenever a
   /// Value is deleted.
+  public:
   class SCEVCallbackVH final : public CallbackVH {
     ScalarEvolution *SE;

@@ -1388,8 +1389,12 @@ private:
     void allUsesReplacedWith(Value *New) override;

