   friend class SCEVCallbackVH;
   friend class SCEVExpander;
@@ -1437,7 +1442,7 @@ private:

   /// The type for ValueExprMap.
   using ValueExprMapType =
-      DenseMap<SCEVCallbackVH, const SCEV *, DenseMapInfo<Value *>>;
+      DenseMap<SCEVCallbackVH, const SCEV *, DenseMapInfo<SCEVCallbackVH>>;

   /// This is a cache of the values we have analyzed so far.
   ValueExprMapType ValueExprMap;
@@ -2481,4 +2486,58 @@ template <> struct DenseMapInfo<ScalarEvolution::FoldID> {

 } // end namespace llvm

+
+// DenseMapInfo specialization for ScalarEvolution::SCEVCallbackVH to avoid
+// constructing CallbackVH on DenseMap sentinel pointer values.
+// DenseMapInfo specialization for ScalarEvolution::SCEVCallbackVH to avoid
+// constructing CallbackVH with DenseMap sentinel pointer values.
+namespace llvm {
+template <> struct DenseMapInfo<ScalarEvolution::SCEVCallbackVH> {
+  using KeyT = ScalarEvolution::SCEVCallbackVH;
+  using SEPtr = ScalarEvolution *;
+
+  static inline KeyT getEmptyKey() {
+    return KeyT(nullptr, reinterpret_cast<SEPtr>(-1));
+  }
+  static inline KeyT getTombstoneKey() {
+    return KeyT(nullptr, reinterpret_cast<SEPtr>(-2));
+  }
+
+  static unsigned getHashValue(const KeyT &Key) {
+    if (Value *V = Key.getRawValue())
+      return DenseMapInfo<Value *>::getHashValue(V);
+    return DenseMapInfo<SEPtr>::getHashValue(Key.getSETag());
+  }
+
+  static bool isEqual(const KeyT &LHS, const KeyT &RHS) {
+    Value *LV = LHS.getRawValue();
+    Value *RV = RHS.getRawValue();
+    if (!LV && !RV)
+      return LHS.getSETag() == RHS.getSETag();
+    return LV == RV;
+  }
+
+  // Heterogeneous lookup support for find_as(Value* or const Value*).
+  static inline unsigned getHashValue(Value *V) {
+    return DenseMapInfo<Value *>::getHashValue(V);
+  }
+  static inline unsigned getHashValue(const Value *V) {
+    return DenseMapInfo<const Value *>::getHashValue(V);
+  }
+  static inline bool isEqual(const KeyT &LHS, Value *RV) {
+    return LHS.getRawValue() == RV;
+  }
+  static inline bool isEqual(const KeyT &LHS, const Value *RV) {
+    return LHS.getRawValue() == RV;
+  }
+  static inline bool isEqual(Value *LV, const KeyT &RHS) {
+    return LV == RHS.getRawValue();
+  }
+  static inline bool isEqual(const Value *LV, const KeyT &RHS) {
+    return LV == RHS.getRawValue();
+  }
+};
+} // end namespace llvm
+
+
 #endif // LLVM_ANALYSIS_SCALAREVOLUTION_H
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 659b4c30a58a..cd908003639b 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -6385,14 +6385,50 @@ void LoopVectorizationCostModel::setVectorizedCallDecision(ElementCount VF) {
 }

 bool LoopVectorizationCostModel::shouldConsiderInvariant(Value *Op) {
-  if (!Legal->isInvariant(Op))
-    return false;
-  // Consider Op invariant, if it or its operands aren't predicated
-  // instruction in the loop. In that case, it is not trivially hoistable.
-  return !isa<Instruction>(Op) || !TheLoop->contains(cast<Instruction>(Op)) ||
-         (!isPredicatedInst(cast<Instruction>(Op)) &&
-          all_of(cast<Instruction>(Op)->operands(),
-                 [this](Value *Op) { return shouldConsiderInvariant(Op); }));
+  // Iterative DFS with cycle guard to avoid infinite recursion on cyclic IR (e.g., reductions).
+  SmallPtrSet<Value *, 16> Visiting;
+  SmallPtrSet<Value *, 16> Proven;
+  SmallVector<Value *, 32> Stack;
+  Stack.push_back(Op);
+  while (!Stack.empty()) {
+    Value *V = Stack.back();
+    // If already proven good, pop and continue.
+    if (Proven.contains(V)) {
+      Stack.pop_back();
+      continue;
+    }
+    // Must be loop-invariant according to legality.
+    if (!Legal->isInvariant(V))
+      return false;
+    // Non-instructions or instructions outside the loop are OK.
+    auto *I = dyn_cast<Instruction>(V);
+    if (!I || !TheLoop->contains(I)) {
+      Proven.insert(V);
+      Stack.pop_back();
+      continue;
+    }
+    // Predicated instructions are not trivially hoistable.
+    if (isPredicatedInst(I))
+      return false;
+    // Detect cycles; if we revisit a node in the current path, it is not
+    // trivially hoistable.
+    if (!Visiting.insert(V).second)
+      return false;
+    bool Pushed = false;
+    for (Value *Opnd : I->operands()) {
+      if (!Proven.contains(Opnd)) {
+        Stack.push_back(Opnd);
+        Pushed = true;
+      }
+    }
+    if (!Pushed) {
+      // All operands are proven; this node is proven as well.
+      Proven.insert(V);
+      Visiting.erase(V);
+      Stack.pop_back();
+    }
+  }
+  return true;
 }

